arguments.file_text:
@inject ISettingsService SettingsService

@if (_loading)
{
    <p class="text-muted">Loading profile…</p>
}
else
{
    <section class="profile-section">
        <h4>Profile</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row g-4">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label" for="displayName">Display Name</label>
                    <input id="displayName" class="form-control" @bind="_displayName" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="email">Email</label>
                    <input id="email" type="email" class="form-control" @bind="_email" />
                </div>

                <div class="mb-3">
                    <label class="form-label" for="bio">Bio</label>
                    <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="avatar-preview">
                    <label class="form-label">Avatar Preview</label>
                    <div class="avatar-frame">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                        }
                        else
                        {
                            <div class="avatar-placeholder">No Avatar</div>
                        }
                    </div>
                    <div class="mt-2">
                        <label class="form-label" for="avatarUrl">Avatar URL</label>
                        <input id="avatarUrl" class="form-control form-control-sm" @bind="_avatarUrl" />
                    </div>
                </div>
            </div>
        </div>

        <div class="mt-3 d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">
                Discard Changes
            </button>
        </div>
    </section>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile _savedProfile = default!;

    protected override async Task OnInitializedAsync()
    {
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _savedProfile = updated;
        _message = "Profile saved successfully!";
        _saving = false;
    }

    private void Discard()
    {
        ApplyProfile(_savedProfile);
        _message = null;
    }
}

.profile-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.avatar-frame {
    width: 150px;
    height: 150px;
    border: 2px dashed #dee2e6;
    border-radius: 50%;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    background: #f8f9fa;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    color: #adb5bd;
    font-size: 0.85rem;
}

