arguments.file_text:
@inject ISettingsService SettingsService

@if (_loading)
{
    <p class="text-muted">Loading notification preferences…</p>
}
else
{
    <section class="notifications-section">
        <h4>Notifications</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Notification Channels</h6>

                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="emailNotif"
                           @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>

                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="pushNotif"
                           @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>

                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Muted Channels</h6>
                <p class="text-muted small">Uncheck a channel to unmute it.</p>

                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        <div class="form-check mb-1">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                        </div>
                    }
                }
            </div>
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving…" : "Save Preferences")
        </button>
    </section>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();

    // In a real app these would come from a channel service
    private readonly List<string> _allChannels = ["general", "announcements", "random", "engineering", "design"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleMute(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _message = "Notification preferences saved!";
        _saving = false;
    }
}

.notifications-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.notifications-section .card-title {
    font-weight: 600;
    margin-bottom: 1rem;
}

