{"file_text": "<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="ToggleExpand">
        <h6 class="mb-0">Change Password</h6>
        <span class="expand-icon">@(_expanded ? "▲" : "▼")</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label" for="currentPwd">Current Password</label>
                <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="newPwd">New Password</label>
                <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="confirmPwd">Confirm Password</label>
                <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private bool _saving;
    private string? _message;
    private bool _isError;

    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";

    private void ToggleExpand() => _expanded = !_expanded;

    private async Task UpdatePasswordAsync()
    {
        _message = null;

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _message = "New password cannot be empty.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _message = "New password and confirmation do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _message = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _isError = true;
        }
        _saving = false;
    }
}
