toolArgs.file_text:
@if (Sessions.Count == 0)
{
    <p class="text-muted">No active sessions.</p>
}
else
{
    @if (_confirmingSessionId is not null)
    {
        <div class="alert alert-warning d-flex align-items-center justify-content-between">
            <span>Are you sure you want to revoke this session?</span>
            <div class="d-flex gap-2">
                <button class="btn btn-sm btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                <button class="btn btn-sm btn-outline-secondary" @onclick="CancelRevoke">Cancel</button>
            </div>
        </div>
    }

    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead>
                <tr>
                    <th>Device</th>
                    <th>Location</th>
                    <th>Last Active</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var session in Sessions)
                {
                    <tr class="@(session.Id == CurrentSessionId ? "table-active" : "")">
                        <td>
                            @session.Device
                            @if (session.Id == CurrentSessionId)
                            {
                                <span class="badge bg-success ms-1">Current</span>
                            }
                        </td>
                        <td>@session.Location</td>
                        <td>@session.LastActive.ToString("g")</td>
                        <td>
                            @if (session.Id != CurrentSessionId)
                            {
                                <button class="btn btn-sm btn-outline-danger"
                                        @onclick="() => RequestRevoke(session.Id)"
                                        disabled="@_revoking">
                                    Revoke
                                </button>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<ActiveSession> Sessions { get; set; } = [];

    [Parameter]
    public string? CurrentSessionId { get; set; }

    [Parameter, EditorRequired]
    public EventCallback<string> OnRevoke { get; set; }

    private string? _confirmingSessionId;
    private bool _revoking;

    private void RequestRevoke(string sessionId)
    {
        _confirmingSessionId = sessionId;
    }

    private void CancelRevoke()
    {
        _confirmingSessionId = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_confirmingSessionId is null) return;

        _revoking = true;
        await OnRevoke.InvokeAsync(_confirmingSessionId);
        _confirmingSessionId = null;
        _revoking = false;
    }
}

