arguments.file_text:
@inject ISettingsService SettingsService

@if (_loading)
{
    <p class="text-muted">Loading security settings…</p>
}
else
{
    <section class="security-section">
        <h4>Security</h4>

        <ChangePasswordPanel SettingsService="SettingsService" />

        <div class="card mb-3">
            <div class="card-body">
                <h6 class="card-title">Two-Factor Authentication</h6>
                <div class="d-flex align-items-center gap-3">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_twoFactorEnabled" disabled />
                        <label class="form-check-label" for="twoFactor">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </label>
                    </div>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "✓ Active" : "✗ Inactive")
                    </span>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @_lastPasswordChange.Value.ToString("f")
                    </p>
                }
            </div>
        </div>

        <div class="card">
            <div class="card-body">
                <h6 class="card-title">Active Sessions</h6>
                <ActiveSessionsTable Sessions="_sessions"
                                     CurrentSessionId="@_sessions.FirstOrDefault()?.Id"
                                     OnRevoke="RevokeSessionAsync" />
            </div>
        </div>
    </section>
}

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = [];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = settings.TwoFactorEnabled;
        _lastPasswordChange = settings.LastPasswordChange;
        _sessions = settings.Sessions;
        _loading = false;
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _sessions = _sessions.Where(s => s.Id != sessionId).ToList();
    }
}

.security-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.security-section .card-title {
    font-weight: 600;
    margin-bottom: 1rem;
}

