arguments.file_text:
@inject ISettingsService SettingsService

@if (_loading)
{
    <p class="text-muted">Loading appearance settings…</p>
}
else
{
    <section class="appearance-section">
        <h4>Appearance</h4>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row g-4">
            <div class="col-md-7">
                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme}")" value="@theme"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size}")" value="@size"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-3">
                    <div class="card-body">
                        <h6 class="card-title">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>
                </div>

                <div class="card mb-3">
                    <div class="card-body">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode"
                                   @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving…" : "Save")
                </button>
            </div>

            <div class="col-md-5">
                <div class="card">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body preview-area @GetPreviewClasses()">
                        <h5 class="preview-heading">Preview</h5>
                        <p class="preview-text">
                            This is how your content will look with the selected settings.
                        </p>
                        <div class="preview-meta">
                            Theme: @_theme · Font: @_fontSize · Lang: @_language
                            @if (_compactMode) { <span>· Compact</span> }
                        </div>
                        <button class="btn btn-sm btn-outline-primary mt-2" disabled>
                            Sample Button
                        </button>
                    </div>
                </div>
            </div>
        </div>
    </section>
}

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();

        classes.Add(_theme switch
        {
            "Dark" => "preview-dark",
            _ => "preview-light"
        });

        classes.Add(_fontSize switch
        {
            "Small" => "preview-font-sm",
            "Large" => "preview-font-lg",
            _ => "preview-font-md"
        });

        if (_compactMode)
            classes.Add("preview-compact");

        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }
}

.appearance-section h4 {
    margin-bottom: 1.5rem;
    font-weight: 600;
}

.appearance-section .card-title {
    font-weight: 600;
    margin-bottom: 0.75rem;
}

/* Live Preview Styles */
.preview-area {
    border-radius: 0.375rem;
    transition: all 0.3s ease;
    min-height: 180px;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
}

.preview-dark .preview-heading {
    color: #f0f0f0;
}

.preview-dark .preview-meta {
    color: #a0a0a0;
}

.preview-dark .btn-outline-primary {
    color: #8ab4f8;
    border-color: #8ab4f8;
}

.preview-font-sm {
    font-size: 0.8rem;
}

.preview-font-md {
    font-size: 1rem;
}

.preview-font-lg {
    font-size: 1.2rem;
}

.preview-compact {
    padding: 0.5rem !important;
    line-height: 1.3;
}

.preview-compact .preview-heading {
    margin-bottom: 0.25rem;
}

.preview-compact .preview-text {
    margin-bottom: 0.25rem;
}

.preview-heading {
    font-weight: 600;
}

.preview-meta {
    font-size: 0.8em;
    color: #6c757d;
}

